import { useState, useRef, useEffect, useCallback } from 'react';
import { useSearchParams, Link } from 'react-router-dom';
import { generateTartan, generateVariations, DEFAULT_CONSTRAINTS, CONSTRAINT_PRESETS } from '../core/generator';
import { parseThreadcount, toThreadcountString, generateSignatures } from '../core/sett';
import { renderTartanToCanvas } from '../utils/renderTartan';
import type { GeneratorResult, GeneratorConstraints, WeaveType } from '../core/types';
import WeaveSelector from '../components/WeaveSelector';

const BATCH_SIZE = 9;

// ---------------------------------------------------------------------------
// Tartan grid card (click to select as active)
// ---------------------------------------------------------------------------

function BatchCard({
  result,
  isActive,
  onClick,
}: {
  result: GeneratorResult;
  isActive: boolean;
  onClick: () => void;
}) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [rendered, setRendered] = useState(false);
  const tc = toThreadcountString(result.sett);

  useEffect(() => {
    if (canvasRef.current) {
      renderTartanToCanvas(canvasRef.current, tc, 240);
      setRendered(true);
    }
  }, [tc]);

  return (
    <button
      onClick={onClick}
      className={`w-full aspect-square rounded-lg overflow-hidden border-2 transition-all duration-200
                  ${isActive
                    ? 'border-[var(--accent)] shadow-lg ring-2 ring-[var(--accent)]/20 scale-[1.02]'
                    : 'border-[var(--border)] hover:border-[var(--border-hover)] hover:shadow-md hover:-translate-y-0.5'}`}
    >
      {!rendered && <div className="w-full h-full bg-[var(--border)] animate-pulse" />}
      <canvas
        ref={canvasRef}
        className={`w-full h-full ${rendered ? '' : 'opacity-0 absolute'}`}
        style={{ imageRendering: 'pixelated' }}
      />
    </button>
  );
}

// ---------------------------------------------------------------------------
// Large preview of selected tartan
// ---------------------------------------------------------------------------

function ActivePreview({ threadcount, weave }: { threadcount: string; weave: WeaveType }) {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    if (canvasRef.current) {
      renderTartanToCanvas(canvasRef.current, threadcount, 600, weave);
    }
  }, [threadcount, weave]);

  return (
    <div className="rounded-xl overflow-hidden border border-[var(--border)] bg-[var(--bg-card)] shadow-sm">
      <canvas
        ref={canvasRef}
        className="w-full aspect-square"
        style={{ imageRendering: 'pixelated' }}
      />
    </div>
  );
}

// ---------------------------------------------------------------------------
// Mutation/breed result thumbnail
// ---------------------------------------------------------------------------

function MutationThumb({ result, index, onClick }: {
  result: GeneratorResult;
  index: number;
  onClick: () => void;
}) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [rendered, setRendered] = useState(false);
  const tc = toThreadcountString(result.sett);

  useEffect(() => {
    if (canvasRef.current) {
      renderTartanToCanvas(canvasRef.current, tc, 160);
      setRendered(true);
    }
  }, [tc]);

  return (
    <button onClick={onClick} className="flex-shrink-0 group">
      <div className="w-24 h-24 sm:w-28 sm:h-28 rounded-lg overflow-hidden border border-[var(--border)]
                      transition-all duration-200
                      group-hover:border-[var(--border-hover)] group-hover:shadow-md group-hover:-translate-y-0.5">
        {!rendered && <div className="w-full h-full bg-[var(--border)] animate-pulse" />}
        <canvas
          ref={canvasRef}
          className={`w-full h-full ${rendered ? '' : 'opacity-0 absolute'}`}
          style={{ imageRendering: 'pixelated' }}
        />
      </div>
      <span className="block mt-1 text-[10px] text-[var(--text-tertiary)] text-center font-mono">
        var {index + 1}
      </span>
    </button>
  );
}

// ---------------------------------------------------------------------------
// Main generate page
// ---------------------------------------------------------------------------

export default function GeneratePage() {
  const [searchParams] = useSearchParams();
  const [batch, setBatch] = useState<GeneratorResult[]>([]);
  const [activeIndex, setActiveIndex] = useState(0);
  const [weave, setWeave] = useState<WeaveType>('twill-2-2');
  const [preset, setPreset] = useState<string>('classic');
  const [constraints, setConstraints] = useState<GeneratorConstraints>({
    ...DEFAULT_CONSTRAINTS,
    ...CONSTRAINT_PRESETS['classic'],
  });

  // Breed state
  type MutationType = 'colors' | 'proportions' | 'both';
  const [mutations, setMutations] = useState<GeneratorResult[]>([]);
  const [mutationType, setMutationType] = useState<MutationType>('colors');

  // Check for passed-in threadcount from breed panel or detail page
  const passedTc = searchParams.get('tc');

  // Auto-generate on mount
  useEffect(() => {
    if (passedTc) {
      try {
        const sett = parseThreadcount(passedTc);
        const signature = generateSignatures(sett);
        const fakeResult: GeneratorResult = { sett, seed: 0, constraints, signature };
        setBatch([fakeResult]);
        setActiveIndex(0);
      } catch {
        generateBatch();
      }
    } else {
      generateBatch();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const activeResult = batch[activeIndex] || null;
  const activeThreadcount = activeResult ? toThreadcountString(activeResult.sett) : '';

  function generateBatch() {
    const results: GeneratorResult[] = [];
    for (let i = 0; i < BATCH_SIZE; i++) {
      results.push(generateTartan(constraints));
    }
    setBatch(results);
    setActiveIndex(0);
    setMutations([]);
  }

  function mutateActive() {
    if (!activeResult) return;
    try {
      const results = generateVariations(
        activeResult.sett, 8, mutationType,
        Math.floor(Math.random() * 2147483647)
      );
      setMutations(results);
    } catch (e) {
      console.error('Mutation failed:', e);
    }
  }

  function promoteMutation(result: GeneratorResult) {
    // Replace the active slot with this mutation
    setBatch(prev => {
      const next = [...prev];
      next[activeIndex] = result;
      return next;
    });
    setMutations([]);
  }

  const handlePresetChange = useCallback((newPreset: string) => {
    setPreset(newPreset);
    if (CONSTRAINT_PRESETS[newPreset]) {
      setConstraints({ ...DEFAULT_CONSTRAINTS, ...CONSTRAINT_PRESETS[newPreset] });
    }
  }, []);

  const handleRangeChange = useCallback((
    key: 'colorCount' | 'stripeCount' | 'threadCount' | 'totalThreads',
    bound: 'min' | 'max',
    value: number
  ) => {
    setConstraints((prev) => ({
      ...prev,
      [key]: { ...prev[key], [bound]: value },
    }));
    setPreset('custom');
  }, []);

  return (
    <div className="min-h-screen">
      <div className="max-w-5xl mx-auto px-4 sm:px-6 py-6 sm:py-10">

        {/* Header + controls */}
        <div className="space-y-5 mb-8">
          <div className="flex items-start justify-between flex-wrap gap-4">
            <div>
              <h1 className="text-2xl sm:text-3xl font-serif font-normal text-[var(--text)]">
                Generate
              </h1>
              <p className="text-sm text-[var(--text-secondary)] mt-1">
                {BATCH_SIZE} tartans per batch. Click any to inspect, mutate, or breed.
              </p>
            </div>
            <button
              onClick={generateBatch}
              className="px-6 py-2.5 rounded-lg text-sm font-medium
                         bg-[var(--accent)] text-white
                         hover:opacity-90 transition-all duration-200
                         active:scale-[0.98] whitespace-nowrap"
            >
              New batch
            </button>
          </div>

          {/* Presets (always visible) */}
          <div className="flex gap-2 flex-wrap items-center">
            <span className="text-[10px] font-mono uppercase tracking-widest text-[var(--text-tertiary)] mr-1">
              Style
            </span>
            {['simple', 'classic', 'complex', 'minimal', 'hunting', 'dress'].map((p) => (
              <button
                key={p}
                onClick={() => handlePresetChange(p)}
                className={`pill text-xs capitalize
                  ${preset === p ? 'pill-active' : 'pill-inactive'}`}
              >
                {p}
              </button>
            ))}
          </div>

          {/* Constraint sliders (always visible on desktop, collapsible on mobile) */}
          <details className="sm:open" open>
            <summary className="sm:hidden text-xs text-[var(--text-secondary)] cursor-pointer mb-3">
              Adjust constraints
            </summary>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
              <RangeControl
                label="Colors"
                min={constraints.colorCount.min}
                max={constraints.colorCount.max}
                absMin={2}
                absMax={8}
                onMinChange={(v) => handleRangeChange('colorCount', 'min', v)}
                onMaxChange={(v) => handleRangeChange('colorCount', 'max', v)}
              />
              <RangeControl
                label="Stripes"
                min={constraints.stripeCount.min}
                max={constraints.stripeCount.max}
                absMin={2}
                absMax={16}
                onMinChange={(v) => handleRangeChange('stripeCount', 'min', v)}
                onMaxChange={(v) => handleRangeChange('stripeCount', 'max', v)}
              />
              <RangeControl
                label="Per stripe"
                min={constraints.threadCount.min}
                max={constraints.threadCount.max}
                absMin={2}
                absMax={64}
                onMinChange={(v) => handleRangeChange('threadCount', 'min', v)}
                onMaxChange={(v) => handleRangeChange('threadCount', 'max', v)}
              />
              <RangeControl
                label="Total threads"
                min={constraints.totalThreads.min}
                max={constraints.totalThreads.max}
                absMin={20}
                absMax={400}
                onMinChange={(v) => handleRangeChange('totalThreads', 'min', v)}
                onMaxChange={(v) => handleRangeChange('totalThreads', 'max', v)}
              />
            </div>
          </details>
        </div>

        {/* Two-column layout: batch grid + active detail */}
        <div className="grid grid-cols-1 lg:grid-cols-[1fr_340px] gap-8">

          {/* Batch grid */}
          <div>
            <div className="grid grid-cols-3 gap-3">
              {batch.map((result, i) => (
                <BatchCard
                  key={`${result.seed}-${i}`}
                  result={result}
                  isActive={i === activeIndex}
                  onClick={() => { setActiveIndex(i); setMutations([]); }}
                />
              ))}
            </div>
          </div>

          {/* Active tartan detail sidebar */}
          {activeResult && (
            <div className="space-y-5 lg:sticky lg:top-20 lg:self-start">
              {/* Preview */}
              <ActivePreview threadcount={activeThreadcount} weave={weave} />

              {/* Weave selector */}
              <WeaveSelector
                threadcount={activeThreadcount}
                activeWeave={weave}
                onChange={setWeave}
              />

              {/* Thread count */}
              <div className="bg-[var(--bg-card)] border border-[var(--border)] rounded-lg
                             px-3 py-2 text-xs font-mono text-[var(--text-secondary)]
                             break-all leading-relaxed select-all">
                {activeThreadcount}
              </div>

              {/* Mutate / Breed */}
              <div className="space-y-3">
                <div className="flex items-center justify-between">
                  <span className="text-[10px] font-mono uppercase tracking-widest text-[var(--text-tertiary)]">
                    Mutate
                  </span>
                </div>
                <div className="flex gap-2 flex-wrap">
                  {(['colors', 'proportions', 'both'] as MutationType[]).map((mt) => (
                    <button
                      key={mt}
                      onClick={() => setMutationType(mt)}
                      className={`pill text-xs capitalize
                        ${mutationType === mt ? 'pill-active' : 'pill-inactive'}`}
                    >
                      {mt}
                    </button>
                  ))}
                  <button
                    onClick={mutateActive}
                    className="pill text-xs pill-active ml-auto"
                  >
                    Breed 8
                  </button>
                </div>

                {/* Mutation results */}
                {mutations.length > 0 && (
                  <div className="flex gap-2 overflow-x-auto no-scrollbar pb-1 -mx-1 px-1">
                    {mutations.map((result, i) => (
                      <MutationThumb
                        key={`mut-${result.seed}-${i}`}
                        result={result}
                        index={i}
                        onClick={() => promoteMutation(result)}
                      />
                    ))}
                  </div>
                )}
                {mutations.length > 0 && (
                  <p className="text-[10px] text-[var(--text-tertiary)]">
                    Click a variation to promote it into the grid
                  </p>
                )}
              </div>

              {/* Link to detail page */}
              <Link
                to={`/library/${encodeURIComponent(activeThreadcount)}`}
                className="block text-center text-xs text-[var(--accent)] hover:underline font-medium py-2"
              >
                Open full detail
              </Link>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// Range control
// ---------------------------------------------------------------------------

function RangeControl({
  label,
  min,
  max,
  absMin,
  absMax,
  onMinChange,
  onMaxChange,
}: {
  label: string;
  min: number;
  max: number;
  absMin: number;
  absMax: number;
  onMinChange: (v: number) => void;
  onMaxChange: (v: number) => void;
}) {
  return (
    <div className="bg-[var(--bg-card)] border border-[var(--border)] rounded-lg p-3">
      <label className="text-[10px] font-mono uppercase tracking-widest text-[var(--text-tertiary)] block mb-2">
        {label}
      </label>
      <div className="text-xs text-[var(--text-secondary)] mb-1.5 tabular-nums">
        {min} – {max}
      </div>
      <div className="space-y-1.5">
        <input
          type="range"
          min={absMin}
          max={absMax}
          value={min}
          onChange={(e) => onMinChange(Math.min(Number(e.target.value), max))}
          className="w-full h-1 bg-[var(--border)] rounded-full appearance-none cursor-pointer
                     [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-3 [&::-webkit-slider-thumb]:h-3
                     [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:bg-[var(--accent)]
                     [&::-webkit-slider-thumb]:cursor-pointer"
        />
        <input
          type="range"
          min={absMin}
          max={absMax}
          value={max}
          onChange={(e) => onMaxChange(Math.max(Number(e.target.value), min))}
          className="w-full h-1 bg-[var(--border)] rounded-full appearance-none cursor-pointer
                     [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-3 [&::-webkit-slider-thumb]:h-3
                     [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:bg-[var(--accent)]
                     [&::-webkit-slider-thumb]:cursor-pointer"
        />
      </div>
    </div>
  );
}
